style:
html{scroll-behavior:smooth;scroll-padding-top:92px}
body{margin:0;font-family:"Source Sans 3",ui-sans-serif,system-ui,sans-serif;color:#44392C;background-color:#FAF6EE;background-image:url("data:image/svg+xml,%3Csvg xmlns=%27http://www.w3.org/2000/svg%27 width=%27220%27 height=%27220%27%3E%3Cfilter id=%27n%27%3E%3CfeTurbulence type=%27fractalNoise%27 baseFrequency=%270.85%27 numOctaves=%272%27 stitchTiles=%27stitch%27/%3E%3CfeColorMatrix values=%270 0 0 0 0.35 0 0 0 0 0.28 0 0 0 0 0.19 0 0 0 0.05 0%27/%3E%3C/filter%3E%3Crect width=%27220%27 height=%27220%27 filter=%27url(%23n)%27/%3E%3C/svg%3E");-webkit-font-smoothing:antialiased}
a{color:#A6522A;text-decoration-color:#C96F3B99;text-underline-offset:3px}
a:hover{color:#7E3D1E}
::selection{background:#C96F3B44}
:focus-visible{outline:3px solid #A6522A;outline-offset:2px;border-radius:3px}
@keyframes ssdash{to{stroke-dashoffset:-32}}
@media(min-width:1000px){[data-mobile-only]{display:none !important}[data-with-sidebar]{display:grid;grid-template-columns:minmax(0,1fr) 300px;gap:44px;align-items:start}}
@media(max-width:999px){[data-desktop-only]{display:none !important}}
@media(prefers-reduced-motion:reduce){*{animation:none !important;transition:none !important}html{scroll-behavior:auto}}

.hv0:hover{color:#A6522A;text-decoration:underline;text-underline-offset:4px}
.hv1:hover{background:#B25E2C;transform:translateY(-1px);box-shadow:0 8px 18px -8px rgba(92,68,51,0.5)}.hv1:active{transform:translateY(0)}
.hv2:hover{transform:rotate(0deg) translateY(-4px)}
.hv3:hover{background:#B25E2C;transform:translateY(-1px);box-shadow:0 10px 22px -10px rgba(0,0,0,0.5);color:#FFF9F0}
.hv4:hover{border-color:#2F4A2E}
.hv5:hover{border-color:#C4B896}
.hv6:hover{background:#B25E2C;transform:translateY(-1px);box-shadow:0 10px 22px -10px rgba(0,0,0,0.5)}.hv6:active{transform:translateY(0)}
.hv7:hover{color:#FAF6EE;text-decoration:underline}
[data-if]{display:none}
[data-if].on{display:block}
